INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$PrestaShop 1.6 migration path$q$, $q$Store owners on PrestaShop 1.6 can move to Thirty Bees with relatively low migration friction.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Active security patching$q$, $q$The core team continues to release security and stability updates to the forked codebase.$q$, 7);
