INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$What is Thirty Bees used for$q$, $q$Thirty Bees is used to build and run self-hosted online stores, covering product catalog management, checkout, payments, and order fulfillment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Is Thirty Bees free$q$, $q$Yes, the core Thirty Bees platform is free and open source; merchants only pay for their own hosting and any optional premium modules or themes they choose to buy.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Is Thirty Bees related to PrestaShop$q$, $q$Yes, Thirty Bees began as a fork of PrestaShop 1.6, created to keep that stable codebase updated and patched for merchants.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Do I need technical skills to use Thirty Bees$q$, $q$Basic server administration and installation knowledge is helpful since Thirty Bees is self-hosted rather than a fully managed SaaS product.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Can I migrate from PrestaShop to Thirty Bees$q$, $q$Store owners on PrestaShop 1.6 generally have a relatively smooth migration path given the shared codebase origins.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Who created Thirty Bees$q$, $q$Thirty Bees was created by developers Michael Dekker and Lesley Paone, who together have decades of e-commerce development experience.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Does Thirty Bees support multiple stores$q$, $q$Yes, the platform supports running multiple storefronts from a single installation and back office.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$What are alternatives to Thirty Bees$q$, $q$Common alternatives include PrestaShop, WooCommerce, OpenCart, and hosted platforms like Shopify or BigCommerce.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Migrating from PrestaShop 1.6$q$, $q$Store owners on an aging PrestaShop 1.6 install can move to a maintained, patched fork without a full platform rebuild.$q$, $q$Existing PrestaShop 1.6 merchants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Budget-conscious self-hosted stores$q$, $q$Merchants who want full e-commerce functionality without paying recurring platform subscription fees.$q$, $q$Small and mid-sized online retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Developer-controlled storefronts$q$, $q$Agencies and technical teams that want complete access to source code for deep customization.$q$, $q$Web developers and e-commerce agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$Community Edition$q$, $q$Free$q$, $q$self-hosted$q$, NULL, $q$["Full source code access","Unlimited products and orders","Self-hosted deployment on your own server","Access to the themes and modules marketplace"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$overview$q$, $q$What Is Thirty Bees$q$, 2, ARRAY[$q$Thirty Bees is an open-source e-commerce platform designed to let merchants run a full-featured online store without paying subscription fees for core functionality. It was created by developers Michael Dekker and Lesley Paone as a stabilized fork of PrestaShop 1.6, aimed at store owners who wanted the reliability of that established codebase combined with ongoing security patches, performance work, and new features.$q$, $q$Unlike hosted SaaS platforms, Thirty Bees is self-hosted software: merchants download it and install it on their own server or a compatible hosting provider, giving them full access to the underlying code and complete control over customization, data, and infrastructure choices.$q$, $q$The platform is maintained by its founding team and an open-source community, with development funded through optional paid modules, premium themes, and support services rather than mandatory licensing fees for the base platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Thirty Bees ships with the core toolkit expected of a mature e-commerce platform: product catalog and inventory management, multiple payment gateway integrations, tax and shipping rule configuration, and a back-office dashboard for order and customer management. Because it descends from PrestaShop 1.6, merchants migrating from that platform can move over with minimal friction.$q$, $q$The platform also supports multi-store setups from a single installation, SEO-friendly URL structures, and a marketplace of official and third-party themes and modules that extend functionality for shipping carriers, marketing tools, and payment processors.$q$, $q$A key differentiator is that many features bundled as paid add-ons on other platforms are included in the free core distribution, reflecting the founders' stated goal of building the best free e-commerce platform without nickel-and-diming merchants for essentials.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Thirty Bees platform is completely free and open source under its published license, with no subscription required to run a store. Merchants are responsible for their own hosting costs, since the software is self-hosted rather than provided as a managed cloud service.$q$, $q$Additional revenue comes from optional premium modules and themes sold through the Thirty Bees marketplace, as well as paid technical support and development services for merchants who want professional assistance beyond community forums and documentation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('54196510-1549-49ef-8799-53017ed6e08f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
