INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Implementation and evidence collection still require meaningful internal time investment$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$What is Thoropass$q$, $q$Thoropass is a compliance automation platform, formerly known as Laika, that combines software for evidence collection with an in-house CPA audit team for certifications like SOC 2 and ISO 27001.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Was Thoropass previously called Laika$q$, $q$Yes, the company was founded in 2019 as Laika and rebranded to Thoropass in March 2023.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$What frameworks does Thoropass support$q$, $q$Thoropass supports SOC 1, SOC 2, ISO 27001, HITRUST, PCI DSS, HIPAA, and GDPR compliance programs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$How much does Thoropass cost$q$, $q$Pricing is generally custom, with reported figures around $8,700 to $30,000 per year depending on scope, framework, and whether the audit is bundled with the platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Can Thoropass perform the actual audit, not just prepare for it$q$, $q$Yes, Thoropass operates its own AICPA peer-reviewed CPA audit practice, so it can perform the certification audit as well as the readiness software.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Who is Thoropass best suited for$q$, $q$B2B SaaS companies, fintechs, and other technology businesses that need to earn customer trust through formal security certifications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$What is First Pass in Thoropass$q$, $q$First Pass is Thoropass's AI-assisted review feature that checks collected audit evidence for gaps before formal audit fieldwork begins.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$What are alternatives to Thoropass$q$, $q$Common alternatives include Vanta, Drata, Secureframe, and Sprinto, which offer compliance automation software with varying degrees of audit-firm integration.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$First-time SOC 2 certification$q$, $q$Startups pursuing their first SOC 2 report can use Thoropass to prepare evidence and complete the audit through one vendor.$q$, $q$Early and growth-stage SaaS startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Multi-framework compliance programs$q$, $q$Companies that need SOC 2 plus ISO 27001, HIPAA, or PCI DSS can manage overlapping controls in a single system.$q$, $q$Mid-market and enterprise technology companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Continuous compliance monitoring$q$, $q$Organizations maintaining an existing certification can use ongoing monitoring to stay audit-ready year-round.$q$, $q$Compliance and security teams at regulated SaaS companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Platform Subscription$q$, $q$Approximately $8,700 per year$q$, $q$annual$q$, NULL, $q$["Compliance automation software","Automated evidence collection integrations","Policy templates and readiness dashboards"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$SOC 2 Audit Subscription$q$, $q$Approximately $5,800 per year$q$, $q$annual$q$, NULL, $q$["SOC 2 audit performed by Thoropass's in-house CPA firm","Connected Audit workflow with the platform","First Pass AI evidence review"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$Bundled SOC 2 Type II$q$, $q$Approximately $12,000 to $30,000 per year$q$, $q$annual$q$, NULL, $q$["Platform plus audit bundled together","Reported 25 to 50 percent savings versus separate vendors","Support across multiple compliance frameworks"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$overview$q$, $q$What Is Thoropass$q$, 2, ARRAY[$q$Thoropass is a compliance automation platform built to help technology companies achieve and maintain security certifications such as SOC 2, ISO 27001, HIPAA, PCI DSS, and GDPR. Originally founded in 2019 as Laika, the company rebranded to Thoropass in March 2023 and is headquartered in New York City, with an additional EMEA hub in London opened in late 2024.$q$, $q$What distinguishes Thoropass from many compliance-software competitors is its dual identity: it is both a software platform for automating evidence collection and readiness tracking, and a tech-enabled CPA audit firm in its own right. Thoropass is AICPA peer-reviewed, holds PCI Qualified Security Assessor status, and is a HITRUST Accredited Assessor, letting customers complete both audit preparation and the actual certification audit through one vendor.$q$, $q$The company has raised approximately $98 million in venture funding across multiple rounds, backed by investors including J.P. Morgan Growth Equity Partners, Fin Capital, Canapi Ventures, and Centana Growth Partners, positioning it as a well-capitalized player in the compliance-automation and GRC (governance, risk, and compliance) space.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Thoropass's core offering is its 'Connected Audit' model, which links automated compliance monitoring software directly to its in-house audit team, reducing the friction and duplicated work that typically occurs when a company's compliance platform and its external auditor are separate vendors. The platform continuously monitors cloud, HR, and developer tool integrations to collect evidence automatically rather than relying on manual screenshots and spreadsheets.$q$, $q$An AI-assisted feature called First Pass reviews collected evidence ahead of formal audit fieldwork to flag gaps early, helping teams close compliance holes before the audit clock starts. The platform also includes policy templates, vendor risk management workflows, and dashboards for tracking readiness across multiple frameworks simultaneously.$q$, $q$Because Thoropass supports SOC 1, SOC 2, ISO 27001, HITRUST, PCI DSS, HIPAA, and GDPR, companies pursuing more than one certification can manage overlapping controls from a single system rather than duplicating effort across frameworks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39e085ba-918c-440b-8ad4-af576ba5ba03', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Thoropass does not publish a standard self-serve pricing page; pricing is generally quote-based and depends on company size, frameworks pursued, and whether the audit is bundled with the platform subscription. Publicly referenced figures, such as an AWS Marketplace listing, show a platform subscription around $8,700 per year plus a separate SOC 2 audit subscription around $5,800 per year.$q$, $q$Market-reported pricing for a full bundled SOC 2 Type II engagement, combining the software platform and the audit itself, commonly falls in the $12,000 to $30,000 per year range depending on scope, with Thoropass positioning the bundle as delivering 25 to 50 percent savings compared to paying for a compliance platform and a separate external audit firm.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$500-character text posts$q$, $q$Share short-form text updates alongside links, photos, and video.$q$, 0);
