INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Reply and mention controls$q$, $q$Manage who can mention or reply to your posts, including hidden-word filtering.$q$, 4);
