INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Fediverse interoperability$q$, $q$ActivityPub support lets some Threads content be followed from platforms like Mastodon.$q$, 6);
