INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Requires an Instagram account to join, which is a barrier for non-Instagram users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Algorithmic feed can bury chronological content from followed accounts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$No dedicated native desktop application, only a web version$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Advanced search and discovery tools are more limited than on some rivals$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Subject to the same content moderation and misinformation concerns as other Meta platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$What is Threads$q$, $q$Threads is a free text-based social networking app from Meta, built by the Instagram team and launched in July 2023 as an alternative to X.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$When did Threads launch$q$, $q$Threads officially launched on July 5, 2023.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Is Threads free to use$q$, $q$Yes, Threads is completely free, monetized through advertising rather than subscriptions.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Do I need an Instagram account to use Threads$q$, $q$Yes, signing up for Threads requires logging in with an existing Instagram account.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$What is the character limit on Threads posts$q$, $q$Threads posts can be up to 500 characters long, plus links, photos, and video.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$How is Threads different from X (Twitter)$q$, $q$Threads is tightly integrated with Instagram's social graph, is free of a dedicated verification subscription tier tied to the core product, and supports Fediverse interoperability via ActivityPub, which X does not offer.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Can Threads posts be seen on Mastodon$q$, $q$Yes, through ActivityPub-based Fediverse interoperability, some Threads content can be followed and viewed from platforms like Mastodon.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Does deleting Instagram delete my Threads account$q$, $q$Threads accounts are linked to Instagram accounts, so account management is tied to the associated Instagram profile.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Building a public audience$q$, $q$Creators and public figures use Threads to share short-form updates and engage directly with followers.$q$, $q$Creators, public figures, and brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Cross-posting from Instagram$q$, $q$Brands and creators extend their existing Instagram presence into a text-first conversational format.$q$, $q$Social media marketers and brand teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Real-time public conversation$q$, $q$Everyday users join trending discussions and follow public conversations in a familiar social feed format.$q$, $q$General social media users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$Threads$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited text posts up to 500 characters","Photo and video sharing","Instagram account integration","Ad-supported feed with no subscription required"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$overview$q$, $q$What Is Threads$q$, 2, ARRAY[$q$Threads is a free text-based social networking app developed by Meta Platforms and built by the Instagram team. It launched on July 5, 2023, positioned as a direct alternative to X (formerly Twitter) at a moment when that platform was experiencing significant user and advertiser turbulence.$q$, $q$Rather than building a new identity system from scratch, Meta tied Threads directly to Instagram: users log in with their existing Instagram account, can carry over their username, and can automatically follow the same accounts on Threads that they already follow on Instagram. This one-tap onboarding was a major factor in the app's launch performance.$q$, $q$As a Meta product, Threads is headquartered alongside the rest of the company in Menlo Park, California, and benefits from Meta's existing infrastructure, trust and safety systems, and advertising business rather than operating as an independently funded startup.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Threads supports text posts up to 500 characters, along with links, photos, and videos up to five minutes in length. Standard social interactions are available, including liking, replying, reposting, and quoting posts, with visible counts of likes and replies on each post.$q$, $q$The app includes moderation and control tools such as the ability to manage who can mention or reply to a user's posts and to filter out replies containing specific hidden words, aimed at reducing harassment and unwanted engagement.$q$, $q$Since launch, Meta has expanded Threads with a web version, a chronological following feed option alongside the algorithmic feed, and interoperability with the wider Fediverse through the ActivityPub protocol, letting users on platforms like Mastodon follow and interact with some Threads content.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b1f3b00-6e09-441c-a0b6-e202cea7f985', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Threads is completely free for all users; there is no subscription tier or paywalled feature set required to post, follow, or interact on the platform. Meta monetizes Threads primarily through advertising, consistent with its approach across Facebook and Instagram.$q$, $q$Because Threads relies on an existing Instagram account for sign-up, there is no separate account-creation cost or premium account type, though Meta Verified subscribers on Instagram may see related benefits carry over to their Threads presence.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Credit-based ticketing$q$, $q$Pay per ticket via prepaid or pay-as-you-sell credits instead of a fixed monthly subscription.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Custom-branded checkout$q$, $q$Keep your own branding on the ticket purchase flow rather than a shared marketplace page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Reserved seating charts$q$, $q$Sell assigned seats with visual seating maps for venue-based events.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Box office app$q$, $q$Check attendees in and sell tickets on-site from a mobile box office application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Waitlists$q$, $q$Capture demand for sold-out events and notify attendees when tickets become available.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Payment integrations$q$, $q$Connect Stripe and PayPal to process payments directly to the organizer's own account.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Marketing and workflow integrations$q$, $q$Sync with Mailchimp, Zoom, and Zapier to automate post-purchase and event-day workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Embeddable widgets$q$, $q$Embed a white-label ticket checkout directly on an organizer's own website.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Flat per-ticket fee that is typically lower than percentage-based competitors like Eventbrite$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$No revenue share and no requirement to list events in a public marketplace$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Organizers keep their own branding and full ownership of customer data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Free for events that only offer free tickets, up to a yearly allowance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Long track record as an independent, bootstrapped company since 2010$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Less built-in event discovery traffic than marketplace platforms like Eventbrite$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Reserved seating consumes more credits per ticket than general admission$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Customer support is primarily via chat and email rather than phone$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Native in-person point-of-sale capability is more limited than dedicated venue POS tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$What is Ticket Tailor$q$, $q$Ticket Tailor is a self-service event ticketing platform that charges a low flat fee per ticket instead of a percentage of ticket revenue.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Who founded Ticket Tailor$q$, $q$Ticket Tailor was founded in 2010 by Jonny White in Birmingham, UK.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$How does Ticket Tailor pricing work$q$, $q$Ticket Tailor uses a credit-based system where organizers pay per ticket, either as they sell or by prepaying for volume credit bundles that lower the per-ticket cost.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Is Ticket Tailor free for free events$q$, $q$Yes, events that only offer free tickets can use the platform at no cost up to a yearly free-ticket allowance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$How is Ticket Tailor different from Eventbrite$q$, $q$Ticket Tailor charges a flat per-ticket fee and does not take a percentage of revenue or list events on a shared public marketplace, while Eventbrite operates more as a discovery marketplace with percentage-based fees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Does Ticket Tailor support reserved seating$q$, $q$Yes, organizers can sell assigned seats using visual seating charts in addition to general admission tickets.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Is Ticket Tailor a private or public company$q$, $q$Ticket Tailor is an independent, bootstrapped company; it was briefly owned by Time Out before founder Jonny White reacquired it in 2014.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Do Ticket Tailor credits expire$q$, $q$No, prepaid ticket credits purchased through volume bundles do not expire.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Recurring independent events$q$, $q$Organizers running regular ticketed events benefit from predictable, low per-ticket costs and branded checkout.$q$, $q$Independent event organizers and promoters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Free community events$q$, $q$Nonprofits and community groups can ticket free events at no platform cost up to the yearly allowance.$q$, $q$Nonprofits and community organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Venue and membership ticketing$q$, $q$Venues use white-label embedded checkout and reserved seating to sell tickets directly from their own website.$q$, $q$Venues, theaters, and membership organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Free Events$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Free tickets up to a yearly allowance","Full platform features included","No credit card required to start"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Pay As You Sell$q$, $q$Around $0.65 per paid ticket$q$, $q$per ticket$q$, NULL, $q$["No upfront cost","All platform features included","Pay only as tickets sell"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$Volume Credit Bundles$q$, $q$From around $0.25 per paid ticket$q$, $q$prepaid credits$q$, NULL, $q$["Prepay for credits at a discounted per-ticket rate","Credits do not expire","Lower effective cost at higher sales volume"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$overview$q$, $q$What Is Ticket Tailor$q$, 2, ARRAY[$q$Ticket Tailor is a self-service event ticketing platform founded in 2010 by Jonny White in Birmingham, UK, built as a low-cost alternative to expensive ticketing solutions he encountered while running his own local events listing site. The company was briefly owned by Time Out before White bought it back in 2014 to keep it independent, and it remains a bootstrapped company headquartered in London.$q$, $q$The platform lets event organizers create and sell tickets for events of any size, from small community gatherings to large recurring venue programming, through a fully self-service dashboard rather than requiring a sales relationship with the vendor.$q$, $q$Ticket Tailor's defining trait is its business model: instead of taking a percentage cut of ticket sales like a marketplace, it charges a flat, low fee per ticket and gives organizers full control over branding, checkout experience, and customer data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform provides custom-branded checkout pages, reserved seating charts, general admission ticketing, waitlists, and a box office app for on-the-door check-in and sales, covering the full lifecycle of running a ticketed event.$q$, $q$Ticket Tailor uses a credit-based pricing system where credits are purchased upfront or consumed on a pay-as-you-sell basis; one credit typically covers one general-admission ticket, while a reserved-seat ticket consumes two credits, and unused credits do not expire.$q$, $q$Integrations with tools like Stripe, PayPal, Zoom, Mailchimp, and Zapier let organizers connect ticketing data to payment processing, virtual event delivery, and marketing workflows without needing custom development.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('732a7077-9f6e-449a-947d-9f0d056354b8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Ticket Tailor offers a free tier for events that only issue free tickets, covering up to a set number of free tickets per year at no charge. Paid events are billed per ticket rather than through a monthly subscription, and every plan includes the same full set of platform features.$q$, $q$Organizers can choose pay-as-you-sell pricing at around $0.65 per paid ticket, or prepay for volume credit bundles to bring the effective cost down to as low as roughly $0.25 per ticket, with purchased credits carrying no expiration date.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$MySQL-compatible distributed SQL$q$, $q$Migrate MySQL-based applications with minimal changes while gaining horizontal scalability.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$HTAP architecture$q$, $q$Run transactional and analytical workloads on the same live data without a separate data warehouse.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Serverless autoscaling$q$, $q$The Starter tier automatically scales compute and storage based on consumption.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Built-in vector search$q$, $q$Native vector search capabilities support AI and retrieval-augmented generation applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Multi-cloud availability$q$, $q$Deploy Dedicated clusters on AWS, Google Cloud, or Azure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$High availability via Raft consensus$q$, $q$Multi-replica consensus and multi-region deployment options improve resilience and reduce latency.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$TiFlash columnar engine$q$, $q$A dedicated columnar storage engine accelerates real-time analytical queries.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Streaming and BI integrations$q$, $q$Connects with Kafka, Spark, and standard MySQL-compatible BI tooling.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$MySQL compatibility lowers the barrier to migrating existing applications$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Generous free quota on the serverless Starter tier for smaller workloads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Combines transactional and analytical processing without a separate data warehouse$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Strong horizontal scalability for large or fast-growing datasets$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Active open-source project with a large GitHub community and star count$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Pricing structure spans multiple tiers and billing units, which can be complex to estimate upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Smaller surrounding tooling ecosystem than traditional MySQL or PostgreSQL$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Distributed-systems concepts add a learning curve versus a single-node database$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Premium regions such as Singapore, Tokyo, and Frankfurt cost more than standard US regions$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$What is TiDB Cloud$q$, $q$TiDB Cloud is PingCAP's fully managed cloud service for TiDB, an open-source, MySQL-compatible distributed SQL database.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Who makes TiDB Cloud$q$, $q$TiDB Cloud is made by PingCAP, a company founded in 2015 and headquartered in Sunnyvale, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Is TiDB Cloud open source$q$, $q$TiDB itself is open source; TiDB Cloud is the managed, paid cloud service built on top of the open-source database.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Is TiDB Cloud MySQL compatible$q$, $q$Yes, TiDB Cloud uses the MySQL wire protocol, letting existing MySQL drivers, ORMs, and applications connect with minimal changes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$What are TiDB Cloud's pricing tiers$q$, $q$TiDB Cloud offers a Starter serverless tier with a free quota, an Essential tier with provisioned capacity from around $400 per month, and a Dedicated tier billed hourly per node.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$What is the difference between TiDB and TiDB Cloud$q$, $q$TiDB is the open-source database software that can be self-hosted, while TiDB Cloud is PingCAP's fully managed version that handles provisioning, scaling, and operations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$What is TiDB Cloud used for$q$, $q$It is used for applications needing horizontal scalability beyond single-node MySQL, real-time analytics on live data, and increasingly AI applications using vector search.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Can I run TiDB on-premises instead of TiDB Cloud$q$, $q$Yes, TiDB can be self-hosted on-premises or in a private cloud as an alternative to using the managed TiDB Cloud service.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Scaling beyond single-node MySQL$q$, $q$High-growth applications outgrowing a single MySQL instance can scale horizontally without a full rewrite.$q$, $q$High-growth SaaS and consumer applications$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Real-time analytics on live data$q$, $q$Teams needing analytical queries against current transactional data without a separate data warehouse pipeline.$q$, $q$Data engineering and analytics teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$AI and agentic applications$q$, $q$Applications combining transactional storage with vector search for retrieval-augmented generation and agent workloads.$q$, $q$AI and machine learning engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Starter (Serverless)$q$, $q$Free up to quota, then usage-based$q$, $q$pay-per-use$q$, NULL, $q$["5 GiB row storage free per instance","5 GiB columnar storage free per instance","50 million Request Units free per instance","Up to 5 free instances per organization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Essential$q$, $q$From approximately $400 per month$q$, $q$monthly$q$, NULL, $q$["Provisioned Request Capacity Units","2,000 RCU minimum","Dedicated compute for predictable workloads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$Dedicated$q$, $q$From approximately $0.44 per hour per node$q$, $q$hourly$q$, NULL, $q$["Node-based dedicated clusters","Available on AWS, Google Cloud, and Azure","Enterprise-grade scale and isolation"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$overview$q$, $q$What Is TiDB Cloud$q$, 2, ARRAY[$q$TiDB Cloud is the fully managed cloud database service from PingCAP, the company founded in 2015 that created the open-source TiDB distributed SQL database. Headquartered in Sunnyvale, California, with major engineering operations in China, PingCAP built TiDB to be MySQL-compatible so existing applications can adopt it with relatively low migration effort while gaining horizontal scalability beyond what a single MySQL server can provide.$q$, $q$The defining architectural feature of TiDB is HTAP, or Hybrid Transactional and Analytical Processing. TiDB pairs a distributed row-based storage engine for transactional operations with a columnar storage engine called TiFlash for analytical queries, enabling real-time analytics to run directly against live production data without building a separate data warehouse or ETL pipeline.$q$, $q$TiDB Cloud removes the operational burden of running TiDB yourself by handling provisioning, scaling, backups, and high availability across AWS, Google Cloud, and Azure, and increasingly markets itself toward AI and agentic application workloads by adding native vector search capabilities alongside its transactional and analytical engines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$TiDB Cloud offers horizontal scaling that lets storage and compute grow independently as data volume increases, along with high availability through Raft-based multi-replica consensus and support for multi-region deployments to reduce latency and improve resilience.$q$, $q$The platform's serverless Starter tier autoscales automatically and bills on consumption, making it well-suited for variable or unpredictable workloads, while Essential and Dedicated tiers provide provisioned capacity for teams that need predictable performance at scale.$q$, $q$Additional capabilities include built-in vector search for AI and retrieval-augmented generation workloads, integrations with tools like Kafka and Spark for streaming and analytics pipelines, and MySQL wire-protocol compatibility that lets existing MySQL drivers, ORMs, and BI tools connect with minimal changes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('992455d6-9786-48b9-a8ac-bca905448c06', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TiDB Cloud pricing is structured across three tiers. The Starter (serverless) tier includes a free monthly quota of 5 GiB row storage, 5 GiB columnar storage, and 50 million Request Units per instance, with up to five free instances per organization, then bills per Request Unit and per GiB-month of storage beyond that, with standard US regions costing less than premium regions like Singapore, Tokyo, and Frankfurt.$q$, $q$The Essential tier uses provisioned Request Capacity Units with a 2,000-RCU minimum, running roughly $400 per month on AWS Oregon before storage costs, while the Dedicated tier bills node-based clusters hourly, starting around $0.44 per hour for a 4 vCPU node, and is available across AWS, Google Cloud, and Azure for teams needing enterprise-grade isolation and scale.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Single-file HTML wiki$q$, $q$The entire notebook, including content and interface, lives in one portable, offline-capable HTML file.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Tiddler-based content model$q$, $q$Notes are broken into small, taggable, cross-linkable units for non-linear organization.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Powerful filtering and querying$q$, $q$Dynamically surface and organize tiddlers using TiddlyWiki's built-in filter syntax.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Plugin architecture$q$, $q$Extend functionality with community and official plugins for themes, syncing, and automation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Optional Node.js server mode$q$, $q$Run TiddlyWiki as a server-backed application with filesystem storage for multi-user setups.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$WikiText markup with live preview$q$, $q$Write and format content using TiddlyWiki's own markup language with immediate rendering.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Macros and templating$q$, $q$Build custom layouts, dashboards, and interactive views within the wiki itself.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$No account or cloud dependency$q$, $q$Fully local-first operation with no required sign-up or external service.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Completely free and open source with no subscription or account required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Extremely portable since the whole notebook can be a single file$q$, 1);
