INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$No vendor lock-in since data is stored in plain, user-owned files$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Steep learning curve for WikiText syntax and the tiddler-based mental model$q$, 0);
