INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$What is TiddlyWiki$q$, $q$TiddlyWiki is a free, open-source personal wiki that runs as a single self-contained HTML file for organizing non-linear notes called tiddlers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Who created TiddlyWiki$q$, $q$TiddlyWiki was created by British software developer Jeremy Ruston and first released on September 20, 2004.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Is TiddlyWiki free$q$, $q$Yes, TiddlyWiki is completely free and open source with no subscription or paid tiers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Does TiddlyWiki require an internet connection$q$, $q$No, TiddlyWiki works fully offline since the entire application can run from a local HTML file.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$What is a tiddler in TiddlyWiki$q$, $q$A tiddler is the atomic unit of content in TiddlyWiki, a small, taggable, linkable piece of information that can be combined with other tiddlers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Can TiddlyWiki sync across devices$q$, $q$TiddlyWiki does not include built-in cloud sync by default, but users can set up syncing manually or through third-party plugins and services.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$How is TiddlyWiki different from Notion or Obsidian$q$, $q$TiddlyWiki is free, open source, and file-based with no company behind it, while Notion and Obsidian are commercial products with cloud accounts and different pricing models.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Is TiddlyWiki still actively maintained$q$, $q$Yes, TiddlyWiki 5, released in 2013, is actively maintained by its creator and a long-running open-source community.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Self-hosted developer knowledge base$q$, $q$Developers and technical writers build a file-based, plugin-extensible knowledge base without relying on a hosted service.$q$, $q$Developers and technical writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Non-linear research notes$q$, $q$Researchers use tiddlers, tags, and links to organize complex, interconnected notes and references.$q$, $q$Researchers and academics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$Privacy-first personal notebook$q$, $q$Privacy-conscious users keep a fully offline, local-first notebook with no cloud account required.$q$, $q$Privacy-conscious individual users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$TiddlyWiki$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source single-file wiki","Unlimited tiddlers and notes","Plugin and theme ecosystem","Optional Node.js server mode for filesystem storage"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$overview$q$, $q$What Is TiddlyWiki$q$, 2, ARRAY[$q$TiddlyWiki is a free, open-source personal wiki created by developer Jeremy Ruston and first released on September 20, 2004. It was built as a non-linear personal notebook, inspired by Ward Cunningham's original WikiWikiWeb, with the goal of letting people capture, organize, and interlink complex information without relying on a server, database, or cloud account.$q$, $q$The defining trait of TiddlyWiki is that its entire application, including content, interface, and logic, can live inside a single, self-contained HTML file. Users can open that file directly in a web browser, edit it in place, and save it back to disk, making the tool fully portable, offline-capable, and free of external dependencies.$q$, $q$TiddlyWiki 5, released in 2013, remains actively maintained by Ruston and a long-running open-source community. It extended the original concept with a plugin architecture, customizable theming, and an optional Node.js server mode for filesystem-based storage and more advanced, multi-user configurations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Content in TiddlyWiki is broken into small, atomic units called tiddlers, which can be freely tagged, cross-linked, and transcluded into other tiddlers, enabling a genuinely non-linear way of structuring notes rather than a rigid folder or notebook hierarchy.$q$, $q$The platform supports a powerful filtering and querying system for surfacing and organizing tiddlers dynamically, along with macros and templating tools that let advanced users build custom layouts, dashboards, and interactive views entirely within the wiki itself.$q$, $q$TiddlyWiki's plugin ecosystem extends its core functionality with new rendering engines, themes, syncing adapters, and automation tools, while the optional Node.js server mode allows filesystem-based storage and multi-user or server-hosted deployments beyond the single-file model.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TiddlyWiki is completely free and open source, with no subscription, license fee, or account requirement of any kind. Anyone can download the single HTML file or run the Node.js version at no cost.$q$, $q$Because it is a community-maintained open-source project rather than a commercial company, there are no paid tiers, enterprise plans, or vendor support contracts; support instead comes from community documentation, forums, and the plugin ecosystem.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9083bc49-72a1-47d8-94f0-9eca973868b2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
