INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$What is Tidio used for$q$, $q$Tidio is used for live chat, AI-powered chatbot support, and helpdesk ticketing to manage customer service and sales conversations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Is Tidio free$q$, $q$Yes, Tidio offers a free plan with 50 billable conversations per month and up to 10 seats; paid plans start at around $24.17 per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Who founded Tidio$q$, $q$Tidio was founded in 2013 in Szczecin, Poland, by CEO Tytus Golas.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$What is Lyro in Tidio$q$, $q$Lyro is Tidio's AI chatbot that can hold natural conversations with customers and autonomously resolve common support requests.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Does Tidio work with Shopify and WordPress$q$, $q$Yes, Tidio integrates with Shopify, WordPress, and more than 30 other third-party apps.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$How does Tidio pricing scale$q$, $q$Tidio pricing scales by the number of billable conversations per month rather than by the number of agent seats.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Where is Tidio headquartered$q$, $q$Tidio's main headquarters is in San Francisco, California, with additional offices in Szczecin and Warsaw, Poland.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$What are alternatives to Tidio$q$, $q$Common alternatives include Intercom, Zendesk, Crisp, and LiveChat, which offer similar live chat and helpdesk functionality.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$E-commerce pre-sale and support chat$q$, $q$Online stores use live chat and Lyro to answer product questions and reduce cart abandonment.$q$, $q$E-commerce store owners$q$, 0);
