INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Plus$q$, $q$From $300/month plus usage$q$, $q$monthly$q$, NULL, $q$["Custom billable conversations","Dedicated success manager","Multiproject support and custom branding","OpenAPI access"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$Premium$q$, $q$Custom$q$, $q$annual/custom$q$, NULL, $q$["Guaranteed 50 percent Lyro AI resolution rate","3,000+ Lyro AI conversations","Mobile SDK and SSO","Advanced Copilot and compliance features"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$overview$q$, $q$What Is Tidio$q$, 2, ARRAY[$q$Tidio is a customer service platform founded in 2013 in Szczecin, Poland, by CEO Tytus Golas. The company has grown to more than 180 employees, with its main headquarters now in San Francisco, California, and continued operations in Szczecin and Warsaw, Poland.$q$, $q$The platform brings together live chat, an AI chatbot called Lyro, and a helpdesk-style ticketing inbox in a single product, aimed primarily at small and mid-sized businesses that want to offer responsive customer support and sales assistance without building a large support team or implementing complex enterprise software.$q$, $q$Tidio reports serving more than 300,000 businesses worldwide, including well-known brands such as The Body Shop, Under Armour, and Jaguar, and integrates with popular e-commerce and content platforms like Shopify and WordPress.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Tidio is a customizable live chat widget that businesses embed on their website to talk with visitors in real time, paired with a unified inbox that also handles email, Messenger, Instagram, and WhatsApp conversations from one dashboard.$q$, $q$The Lyro AI chatbot can hold natural conversations with customers and autonomously resolve common support questions, reducing the volume of tickets that require a human agent, while Tidio's no-code Flows builder lets teams design chatbot logic and automated workflows without writing code.$q$, $q$Additional capabilities include visitor tracking and analytics, pre-built chatbot templates for common use cases, automatic chat assignment and satisfaction surveys on higher plans, and integrations with more than 30 third-party apps for e-commerce, marketing, and support workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6e610684-65a5-4699-9418-e1149b45dc11', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Tidio uses a freemium model with pricing that scales primarily by billable conversation volume rather than by number of agent seats. The Free plan includes 50 billable conversations per month and up to 10 seats with basic live chat, ticketing, and analytics.$q$, $q$Paid plans start with Starter at around $24.17 per month for 100 billable conversations and 50 Lyro AI conversations, followed by Growth from around $49.17 per month with advanced analytics and automation, Plus from around $300 per month plus usage for larger teams needing dedicated support, and a custom-priced Premium tier offering a guaranteed AI resolution rate, mobile SDK access, SSO, and compliance features. All paid plans include a seven-day free trial without requiring credit card details.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$XMPP/Jabber protocol server$q$, $q$Implements the open, federated XMPP messaging and presence protocol standard.$q$, 0);
