INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$What is Tigase$q$, $q$Tigase is an open-source, Java-based XMPP (Jabber) server used to build real-time messaging, presence, and communication systems.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Is Tigase free to use$q$, $q$Yes, Tigase XMPP Server is free and open source under the AGPLv3 license; a separate commercial license is available for proprietary use cases.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Who created Tigase$q$, $q$The Tigase project was started by developer Artur Hefczyc in October 2004, with Tigase, Inc. formally founded in 2010.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$What protocol does Tigase use$q$, $q$Tigase implements XMPP, also known as Jabber, an open, federated messaging and presence protocol standard.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Does Tigase support group chat$q$, $q$Yes, Tigase supports multi-user chat (MUC) for group conversations as well as PubSub for publish-subscribe messaging.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Can Tigase scale to large user bases$q$, $q$Yes, Tigase supports horizontal clustering, allowing deployments to scale across multiple nodes for high availability and large user counts.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Is Tigase used for IoT messaging$q$, $q$Yes, Tigase's lightweight presence and messaging capabilities are also positioned for IoT communication use cases.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$How much does Tigase's commercial license cost$q$, $q$Commercial licensing and support pricing are not publicly published and require contacting Tigase's sales team for a custom quote.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Self-hosted enterprise messaging$q$, $q$Enterprises needing standards-based, self-hosted real-time messaging with full control over their infrastructure.$q$, $q$Enterprise IT and communications teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$IoT presence and messaging$q$, $q$IoT platforms use Tigase's lightweight protocol support for device presence and messaging.$q$, $q$IoT platform developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Compliance-sensitive chat infrastructure$q$, $q$Organizations needing data residency and compliance control build secure chat systems on Tigase rather than third-party hosted APIs.$q$, $q$Regulated industries and security-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Open Source (AGPLv3)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full XMPP server source code","Community support and documentation","Unlimited self-hosted deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$Commercial License$q$, $q$Custom (contact sales)$q$, $q$annual/custom$q$, NULL, $q$["Proprietary licensing for closed-source deployments","Technical support options","Custom development and consulting services"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$overview$q$, $q$What Is Tigase$q$, 2, ARRAY[$q$Tigase is a high-performance XMPP (Jabber) server used to build real-time messaging, presence, and communication systems. Its origins go back to an open-source project started by developer Artur Hefczyc in October 2004, and the commercial company behind it, Tigase, Inc., was formally founded in 2010 and is headquartered in San Francisco, California.$q$, $q$Tigase XMPP Server is written in Java and implements the open XMPP protocol standard, the same decentralized, federated messaging protocol historically used by Jabber-based chat systems. Tigase has also been an active sponsor of the XMPP Standards Foundation, contributing to the evolution of the protocol itself alongside its server products.$q$, $q$The software is dual-licensed, offered as fully free and open source under the AGPLv3 license, with an optional commercial license available for organizations that need to build closed-source or proprietary products without AGPLv3's copyleft requirements.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Tigase supports horizontal clustering, allowing deployments to scale across multiple nodes for high availability and larger user bases, along with a pluggable component architecture that lets administrators extend or customize server behavior without modifying the core codebase.$q$, $q$The server implements key XMPP extensions such as multi-user chat (MUC) for group conversations and PubSub for publish-subscribe messaging patterns, and it exposes REST and WebSocket APIs so modern web and mobile clients can integrate without needing native XMPP client libraries.$q$, $q$Tigase also provides its own client libraries for iOS, Android, and desktop platforms, along with support for push notifications and mobile-optimized connection handling, and has positioned its technology for IoT messaging use cases in addition to traditional chat applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The open-source edition of Tigase XMPP Server is free to use under the AGPLv3 license, with full access to the source code for self-hosted deployment at any scale.$q$, $q$For organizations that cannot comply with AGPLv3's copyleft terms, Tigase offers a commercial license along with separate technical support plans; pricing for both is not publicly published and is provided on a custom basis by contacting Tigase's sales team, with tiers historically differentiated by deployment size, from smaller systems up to large-scale deployments with 100,000 or more users.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('93755188-c1ee-4269-9581-f911c716c21f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
