-- Enrichment marathon batch: Thirty Bees, Thoropass, Threads, Ticket Tailor, TiDB Cloud, TiddlyWiki, Tidio, Tigase

-- ── Thirty Bees ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Thirty Bees is a free, open-source e-commerce platform forked from PrestaShop 1.6, built to give merchants a stable, self-hosted online store without recurring subscription fees.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Middelburg, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Thirty Bees Review: Free Open-Source Ecommerce Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Thirty Bees is a free, open-source ecommerce platform forked from PrestaShop 1.6. Read features, pricing, pros, and cons in this in-depth review.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Thirty Bees is a free, open-source e-commerce platform created by Michael Dekker and Lesley Paone, two developers with a combined 30-plus years of e-commerce experience. It launched as a fork of PrestaShop 1.6, built specifically to give merchants who relied on that codebase a stable, actively patched alternative after uncertainty grew around PrestaShop's newer 1.7 branch. Rather than rewriting the platform from scratch, the founders focused on stabilizing, securing, and extending the proven 1.6 codebase with performance improvements and new built-in features that previously required paid modules. Thirty Bees is entirely self-hosted: merchants download the software, install it on their own server or hosting provider, and own their code and data outright. There is no monthly subscription for the core platform, which distinguishes it from SaaS competitors like Shopify or BigCommerce. Revenue instead comes from optional premium modules, themes, and paid support offered by the company and its partner network. Because it shares DNA with PrestaShop, Thirty Bees supports familiar e-commerce essentials: product catalog management, multiple payment gateways, multi-store operation from a single back office, SEO-friendly URLs, and a marketplace of themes and modules. It appeals most to small and mid-sized merchants, agencies, and developers who migrated from PrestaShop 1.6 and want continuity without forced upgrades, as well as technically capable store owners who prioritize full ownership of their storefront's code over the convenience of a hosted SaaS platform. Compared to WooCommerce, it offers a more integrated out-of-the-box e-commerce experience; compared to Shopify, it trades hosted convenience for zero licensing cost and complete control.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '54196510-1549-49ef-8799-53017ed6e08f';

