-- ── Thoropass ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Thoropass is a compliance automation platform that pairs software with an in-house CPA audit team to help companies achieve and maintain SOC 2, ISO 27001, HIPAA, PCI DSS, and other security certifications.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (platform plus audit bundles reported from roughly $8,700/year)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Thoropass Review: Compliance Automation and Audit Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Thoropass combines compliance software with an in-house audit firm for SOC 2, ISO 27001, HIPAA, and PCI DSS. See features, pricing, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Thoropass is a compliance automation company, founded in 2019 under the name Laika and rebranded to Thoropass in March 2023, headquartered in New York with an EMEA hub in London opened in November 2024. What sets Thoropass apart from typical compliance-automation software vendors is that it operates as both a technology platform and a tech-enabled CPA audit firm: it is AICPA peer-reviewed, a PCI Qualified Security Assessor, and a HITRUST Accredited Assessor, meaning customers can run their audit evidence collection and their actual certification audit through a single connected vendor rather than juggling separate software and auditor relationships. Thoropass supports SOC 1, SOC 2, ISO 27001, HITRUST, PCI DSS, HIPAA, and GDPR compliance programs, using automated evidence collection integrations and an AI-assisted review feature called First Pass to speed up audit readiness. The company has raised roughly $98 million across Series A, B, and C rounds, with investors including J.P. Morgan Growth Equity Partners, Fin Capital, Canapi, Centana Growth, and ThirdPrime. Pricing is generally custom and quote-based, though public references such as an AWS Marketplace listing show a platform subscription around $8,700 per year plus a SOC 2 audit subscription around $5,800 per year, and reported market pricing for a bundled SOC 2 Type II engagement (platform and audit) commonly falls between $12,000 and $30,000 annually. This bundled model is positioned to save customers 25 to 50 percent versus coordinating a compliance platform and an external audit firm separately. Thoropass primarily serves B2B SaaS, fintech, and other technology companies that need to earn and maintain customer trust through recognized security certifications, competing with vendors like Vanta, Drata, Secureframe, and Sprinto.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '39e085ba-918c-440b-8ad4-af576ba5ba03';

