-- ── Threads ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Threads is Meta's free text-based social networking app built by the Instagram team, launched in July 2023 to let users share short posts and join public conversations.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$10,001+ employees (Meta Platforms, Inc.)$q$, company_size),
  headquarters = COALESCE($q$Menlo Park, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Threads Review: Meta's Text-Based Social Network Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Threads is Meta's free text-sharing app from the Instagram team. See how it works, key features, pricing, and how it compares to X and Mastodon.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Threads is a free text-based social networking app built by Meta Platforms, specifically by the Instagram product team, and officially launched on July 5, 2023, as a direct competitor to X (formerly Twitter) following turbulence at that platform. Threads is not a standalone company but a product owned and operated by Meta, whose headquarters is in Menlo Park, California. Users sign up with an existing Instagram account, and the app lets people share text posts up to 500 characters along with links, photos, and videos up to five minutes long. Interaction mechanics mirror familiar social feed conventions: likes, replies, reposts, and quotes, alongside tools like hidden-word filters that let users control who can reply to or mention them. Upon launch, Threads became the fastest-growing consumer software application in history at the time, surpassing 100 million signups within its first five days, a record that had previously belonged to ChatGPT; this was driven almost entirely by its one-tap onboarding from Instagram's existing user base. Meta later added a web version in August 2023 and has continued to build out features including a chronological following feed, expanded search, and interoperability with the wider Fediverse via the ActivityPub protocol, allowing some Threads posts to be followed from platforms like Mastodon. Threads is entirely free to use and is monetized through advertising rather than subscriptions, aligning with Meta's broader ad-supported business model across Facebook and Instagram. It differs from X primarily in its tighter integration with Instagram's identity and social graph, its emphasis on 'friendly' community guidelines at launch, and its openness to Fediverse interoperability, an approach X does not offer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9b1f3b00-6e09-441c-a0b6-e202cea7f985';

