-- ── Ticket Tailor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Ticket Tailor is a self-service event ticketing platform that charges a low flat fee per ticket instead of a percentage of sales, letting organizers keep their own branding, data, and customer relationships.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free for free events; from $0.25 per paid ticket on volume bundles$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Ticket Tailor Review: Low-Fee Event Ticketing Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Ticket Tailor is a self-service ticketing platform with low flat per-ticket fees instead of revenue share. See pricing, features, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Ticket Tailor is a self-service event ticketing platform founded in 2010 by Jonny White, a software engineer who was running a local events listing website in Birmingham, UK, and grew frustrated with the expensive ticketing solutions available at the time. He built Ticket Tailor as a simple, low-cost alternative that puts control back in the hands of event organizers. The company was briefly acquired by Time Out in 2012 but White bought it back in 2014 to keep it independent, and it has operated as a bootstrapped, independent business ever since, now with roughly 30 to 40 employees and headquarters in London. Ticket Tailor's core differentiator versus marketplace-style competitors like Eventbrite is its pricing model: rather than taking a percentage of ticket revenue, it charges a low flat fee per ticket, moving in 2025 to a credit-based system where one credit equals one general-admission ticket and two credits equal one reserved-seat ticket. Pricing runs from around $0.65 per ticket on a pay-as-you-sell basis down to roughly $0.25 per ticket when organizers prepay for volume credit bundles, with credits that do not expire. Events that only offer free tickets can use the platform at no cost up to a yearly free-ticket allowance. Every plan includes the same full feature set, so the only real variable between customers is ticket volume rather than which features are unlocked. Ticket Tailor positions itself explicitly as a SaaS tool rather than a marketplace: organizers keep their own branding on the checkout page, retain ownership of attendee data, and are not required to list their event in a public discovery marketplace. This makes it popular with independent event organizers, membership and community groups, venues, and nonprofits that want predictable, low-cost ticketing without giving up control of the customer relationship.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '732a7077-9f6e-449a-947d-9f0d056354b8';

