-- ── TiDB Cloud ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TiDB Cloud is PingCAP's fully managed cloud database service for TiDB, an open-source, MySQL-compatible distributed SQL database that handles both transactional and analytical workloads in one system.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter serverless tier with monthly usage quota)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$501-1000 employees$q$, company_size),
  headquarters = COALESCE($q$Sunnyvale, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$TiDB Cloud Review: PingCAP's Managed Distributed SQL Database$q$, seo_title),
  seo_meta_description = COALESCE($q$TiDB Cloud is PingCAP's managed, MySQL-compatible distributed SQL database. See pricing tiers, features, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TiDB Cloud is the fully managed cloud database service built and operated by PingCAP, the company behind the open-source TiDB distributed SQL database. PingCAP was founded in 2015 and is headquartered in Sunnyvale, California, with significant engineering presence in China, and employs several hundred people globally. TiDB itself is one of the most widely adopted open-source distributed SQL databases, with over 33,000 GitHub stars, and is MySQL-compatible, meaning applications built for MySQL can generally migrate with minimal changes while gaining horizontal scalability that a single-node MySQL instance cannot provide. TiDB's core architectural differentiator is HTAP (Hybrid Transactional and Analytical Processing): it combines a row-based storage engine (TiKV) for transactional workloads with a columnar storage engine (TiFlash) for analytical queries, allowing real-time analytics to run directly against live transactional data without a separate ETL pipeline into a data warehouse. TiDB Cloud packages this technology into three main pricing tiers: a Starter serverless tier with a generous free monthly quota (5 GiB row storage, 5 GiB columnar storage, and 50 million Request Units per instance) that then bills on consumption; an Essential tier with provisioned Request Capacity Units starting around $400 per month; and a Dedicated tier with node-based clusters billed hourly, starting around $0.44 per hour, available on AWS, Google Cloud, and Azure. TiDB Cloud increasingly targets AI and agentic application workloads with built-in vector search alongside its transactional and analytical capabilities, positioning it against alternatives like Amazon Aurora, CockroachDB, Google Cloud Spanner, PlanetScale, and Yugabyte for teams that need MySQL compatibility combined with distributed scale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '992455d6-9786-48b9-a8ac-bca905448c06';

