-- ── TiddlyWiki ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TiddlyWiki is a free, open-source personal wiki that runs as a single self-contained HTML file, letting users capture, organize, and interlink notes called tiddlers without needing a server or database.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TiddlyWiki Review: Free Open-Source Personal Wiki Notebook$q$, seo_title),
  seo_meta_description = COALESCE($q$TiddlyWiki is a free, open-source single-file personal wiki for non-linear note-taking. See features, pricing, pros, cons, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TiddlyWiki is a free, open-source personal wiki created by British software developer Jeremy Ruston, first released on September 20, 2004. It was inspired by Ward Cunningham's original WikiWikiWeb concept, and its goal from the start was to provide a portable, single-file personal notebook for capturing and organizing complex, non-linear information. Unlike conventional note apps that require a server, database, or cloud account, TiddlyWiki's entire application, including content, interface, and logic, can live inside one self-contained HTML file that opens and runs directly in a web browser, making it inherently portable, offline-capable, and easy to archive or share without external dependencies. Content in TiddlyWiki is organized into small, reusable units called tiddlers, which can be freely tagged, linked, and transcluded into one another, supporting a genuinely non-linear way of structuring notes rather than a rigid folder hierarchy. TiddlyWiki 5, released in 2013 and still actively maintained today, expanded the original concept with a plugin architecture, theming support, and an optional Node.js server mode that enables filesystem-based storage, multi-user setups, and integration with external tools and automation. TiddlyWiki is entirely free and open source, developed by Ruston and a long-running community of contributors rather than a commercial company, so there is no vendor, subscription, or headquarters behind it in the traditional sense. It is often compared to modern proprietary note-taking tools like Notion or Obsidian, appealing especially to developers, researchers, and privacy-conscious users who want a local-first, fully customizable, and vendor-independent alternative, at the cost of a steeper learning curve and a less polished out-of-the-box interface than mainstream commercial competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9083bc49-72a1-47d8-94f0-9eca973868b2';

