-- ── Tidio ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tidio is a customer service platform combining live chat, the Lyro AI chatbot, and a helpdesk ticketing system to help small and mid-sized businesses handle support and sales conversations.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $24.17/month)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$180-250 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Polish$q$]::text[],
  seo_title = COALESCE($q$Tidio Review: Live Chat, AI Chatbot, and Helpdesk Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Tidio combines live chat, the Lyro AI chatbot, and helpdesk ticketing for small business support. See pricing plans, features, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tidio is a customer service software company founded in 2013 in Szczecin, Poland, by CEO Tytus Golas, and has since grown to more than 180 employees with its main headquarters now in San Francisco, California, alongside offices in Szczecin and Warsaw, Poland. The platform combines three core capabilities: a live chat widget for real-time website conversations, an AI chatbot called Lyro that can autonomously resolve customer support conversations, and a helpdesk-style ticketing inbox that consolidates messages from live chat, email, and social channels like Messenger, Instagram, and WhatsApp into one place. Tidio also offers a no-code automation builder called Flows for creating chatbot and workflow logic without writing code. Tidio reports being used by more than 300,000 businesses, including recognizable brands such as The Body Shop, Under Armour, and Jaguar, and integrates with platforms like Shopify and WordPress plus dozens of other third-party apps. Pricing follows a freemium model: a Free plan supports up to 50 billable conversations per month and 10 seats, while paid plans scale by conversation volume rather than by agent seat count. The Starter plan begins around $24.17 per month for 100 billable conversations and 50 Lyro AI conversations, Growth starts around $49.17 per month with advanced analytics and automatic chat assignment, Plus starts around $300 per month plus usage for larger teams needing dedicated support and custom branding, and Premium is custom-priced for organizations wanting a guaranteed AI resolution rate, SSO, and compliance features. Tidio positions itself as a more affordable, easier-to-implement alternative to enterprise customer service platforms like Zendesk or Intercom, aimed particularly at e-commerce stores and small-to-mid-sized SaaS companies that want AI-assisted support without a lengthy implementation process.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6e610684-65a5-4699-9418-e1149b45dc11';

