-- ── Tigase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tigase is a high-performance, open-source XMPP/Jabber server written in Java for building real-time messaging, presence, and IoT communication systems, available under AGPLv3 or a commercial license.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (AGPLv3); commercial licensing available on request$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tigase Review: Open-Source XMPP Server for Real-Time Messaging$q$, seo_title),
  seo_meta_description = COALESCE($q$Tigase is an open-source, Java-based XMPP server for real-time messaging, presence, and IoT. See features, licensing, and pricing options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tigase is an XMPP (Jabber) server platform whose origins trace back to an open-source project started by developer Artur Hefczyc in October 2004; the commercial entity, Tigase, Inc., was formally founded in 2010 and is headquartered in San Francisco, California. Tigase XMPP Server is written in Java and provides the core infrastructure for building real-time instant messaging, presence, and communication systems based on the open XMPP protocol standard. The software is dual-licensed: it is fully free and open source under the AGPLv3 license for developers who can comply with that license's requirements, and Tigase also offers an optional commercial license for organizations that need to build closed-source or proprietary products on top of the server without AGPLv3's copyleft obligations. As an active sponsor of the XMPP Standards Foundation, Tigase has long been involved in shaping the protocol itself alongside building server implementations. Key technical capabilities include horizontal clustering for high-availability deployments, a pluggable component architecture for extending server functionality, support for XMPP extensions like multi-user chat (MUC) and PubSub, REST and WebSocket APIs for modern client integration, and client libraries for iOS, Android, and desktop platforms. Because XMPP is a mature, standards-based, decentralized messaging protocol (also used by systems like Jabber-based chat networks and some IoT messaging platforms), Tigase is often chosen by organizations that need self-hosted control over their messaging infrastructure, data residency, and compliance posture rather than relying on a third-party hosted chat API. Pricing for the open-source edition is free; commercial licensing, technical support, and custom development pricing are not publicly published and require contacting Tigase's sales team directly, with support plans historically referenced under names like Basic, Standard, and Community tiers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '93755188-c1ee-4269-9581-f911c716c21f';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '93755188-c1ee-4269-9581-f911c716c21f' AND logo IS NULL AND website IS NOT NULL;

